                    assistant_err.append((e['line'],stop,m.get('errorMessage')))
                cont=m.get('content') or []
                for part in cont:
                    if part.get('type')=='toolCall':
                        tool_call_ids.append((e['line'],part.get('id'),part.get('name')))
                    if part.get('type')=='text':
                        txt=part.get('text','')
                        if '(running...)' in txt or 'running...' in txt:
                            running_mentions.append((e['line'],txt[:120]))
            elif role=='toolResult':
                tcid=m.get('toolCallId');
