        if len(gaps)>10: print(f'  ... {len(gaps)-10} more')
    else:
        print('gaps >=30s: none')

    print('toolResult isError count:',len(err_tool))
    for line,name,txt in err_tool[:5]:
        print(f'  line {line} [{name}] {txt.replace(chr(10)," ")[:120]}')
    if len(err_tool)>5: print(f'  ... {len(err_tool)-5} more')

    print('assistant error/aborted count:',len(assistant_err))
    for line,stop,msg in assistant_err:
        print(f'  line {line} stop={stop} err={msg}')

    print('mentions of running/loading text:',len(running_mentions))
    for line,txt in running_mentions[:5]:
        print(f'  line {line} {txt.replace(chr(10)," ")[:120]}')

    print('"(no output)" tool results:',len(no_output))
    if no_output:
        print('  lines:',', '.join(str(l) for l,_ in no_output[:10]))
        if len(no_output)>10: print('  ...')

    print('unmatched toolCall ids:',len(unmatched_calls))
    for line,cid,name in unmatched_calls[:5]:
        print(f'  line {line} toolCall {name} id={cid}')
    if len(unmatched_calls)>5: print(f'  ... {len(unmatched_calls)-5} more')

    print('orphan toolResult ids:',len(orphan_results))
    for line,cid,name in orphan_results[:5]:
        print(f'  line {line} toolResult {name} id={cid}')

    last_role=None
    for e in reversed(events):
        if 'obj' in e and e['obj'].get('type')=='message':
            last_role=e['obj'].get('message',{}).get('role')
            last_line=e['line']
            break
    print('last message role/line:',last_role,last_line if 'last_line' in locals() else None)
    print('last assistant line:',final_assistant_line,'last assistant stop line:',final_assistant_stop_line)
