                a=datetime.datetime.fromisoformat(prev_ts.replace('Z','+00:00'))
                b=datetime.datetime.fromisoformat(ts.replace('Z','+00:00'))
                g=(b-a).total_seconds()
                if g>=30: long_gaps.append((prev_line,i,g))
            except: pass
        if ts: prev_ts=ts; prev_line=i
        if o.get('type')!='message':
            continue
