            if sr=='stop': stop+=1; assistant_stop_lines.append(i)
            if sr=='aborted': aborted+=1
            if sr=='error': errorstop+=1
            for part in m.get('content',[]):
                if part.get('type')=='toolCall':
                    tool_calls.append((i,part.get('id'),part.get('name')))
        elif role=='toolResult':
            if isinstance(m.get('content'),list):
                for part in m['content']:
                    if part.get('type')=='text' and (part.get('text') or '').strip()=='(no output)':
                        no_output.append(i)
            tcid=m.get('toolCallId')
            if tcid: tool_results.append((i,tcid,m.get('toolName')))
        elif role=='user':
            users.append((i,ts))
