                nxt=(i2,ts2); break
        if nxt and ts and nxt[1]:
            try:
                d=(datetime.datetime.fromisoformat(nxt[1].replace('Z','+00:00'))-datetime.datetime.fromisoformat(ts.replace('Z','+00:00'))).total_seconds()
            except: d=None
            lat.append((i,nxt[0],d))
        else:
            lat.append((i,None,None))

    print(f'\n{os.path.basename(p)} lines={len(lines)} toolUse={tooluse} stop={stop} aborted={aborted} errorStop={errorstop} no_output={len(no_output)} unmatched={len(unmatched)} longgaps={len(long_gaps)}')
    if long_gaps:
        print(' long gaps sample:',long_gaps[:4])
    if unmatched:
        print(' unmatched sample:',unmatched[:3])
    if no_output:
        print(' no_output lines:',no_output[:6])
    if lat:
        print(' user->next stop:',lat)
