ids={r[1] for r in results}
un=[c for c in calls if c[1] not in ids]
print('lines',len(lines),'calls',len(calls),'results',len(results),'unmatched',len(un))
if un:
    print('last unmatched',un[-1])
# stop reasons summary վերջին 20 assistant messages
assist=[(i,o['message'].get('stopReason'),o['message'].get('errorMessage')) for i,o in enumerate(objs,1) if o.get('type')=='message' and o['message'].get('role')=='assistant']
print('assistant total',len(assist),'stops count',sum(1 for x in assist if x[1]=='stop'),'toolUse',sum(1 for x in assist if x[1]=='toolUse'),'error',sum(1 for x in assist if x[1]=='error'),'aborted',sum(1 for x in assist if x[1]=='aborted'))
