# user->next stop lines
msgs=[(i,o['message'].get('role'),o['message'],o.get('timestamp') or o['message'].get('timestamp')) for i,o in enumerate(objs,1) if o.get('type')=='message']
for idx,(i,r,m,ts) in enumerate(msgs):
    if r!='user':
        continue
    nxt=None
    for j in range(idx+1,len(msgs)):
        i2,r2,m2,ts2=msgs[j]
        if r2=='assistant' and m2.get('stopReason')=='stop':
            nxt=i2; break
    print('user line',i,'next stop',nxt)
# search aborted/Thread was aborted string
import re
s='\n'.join(lines)
print('contains stopReason aborted?', '"stopReason":"aborted"' in s)
print('contains Thread was aborted?', 'Thread was aborted' in s)
